#include<bits/stdc++.h>
using namespace std;
priority_queue<int,vector<int>,greater<int> >a[2];
int main(void)
{int n,m,ans=0,t;cin>>n>>m;
    for(int i=1;i<=n;i++){
        cin>>t;
        a[0].push(t);//l
    }
    for(int i=1;i<=m;i++){
        cin>>t;
        a[1].push(t);//Q
    }
    if(n>m){cout<<"you died!";return false;}
    while(!a[0].empty()){
        if(a[1].empty()and!a[0].empty()){cout<<"you died!";return false;}
        if(a[0].top()<=a[1].top()){ans+=a[1].top();a[0].pop();a[1].pop();}
        if(a[0].top()>a[1].top())a[1].pop();  
    }
    cout<<ans;
    return false;
}
